body:
In this section, you can learn how to create a materialized view that stores
cumulative sales data for each month. This view uses data from the `sample_supplies.sales`
and `sample_supplies.purchaseOrders` collections. Then, create a function to update
the materialized view each month.

Before running the application, install the `node-schedule` package in your
`search-materialized-view` project directory. This package is used to schedule the
periodic updates of the materialized view.

```shell
npm install node-schedule
```

Create a `create-update-view.js` file in your `search-materialized-view` project directory,
and copy and paste the following code into the file. This file performs the following
actions:

- Connects to your MongoDB deployment using the connection string

- Immediately updates the `monthlyPhoneTransactions` materialized view by:

  - Filtering transactions with purchase method of `"Phone"`

  - Unwinding the items array to process each item

  - Grouping transactions by month and year

  - Calculating total sales quantity and price for each month

- Sets up a scheduler that runs on the first day of each month at midnight

- Continues running in the background, automatically refreshing the view on schedule

The materialized view stores aggregated data about phone transactions by month,
which can significantly improve query performance for search operations.

```javascript
const { MongoClient } = require('mongodb');
const schedule = require('node-schedule');

// Function to update the materialized view
async function updateMonthlyPhoneTransactions(client, collection) {
    // Create the aggregation pipeline
    const pipeline = [
        { $match: { purchaseMethod: 'Phone' } },
        { $unwind: { path: '$items' } },
        { 
            $group: {
                _id: { 
                    $dateToString: {
                        format: '%Y-%m',
                        date: '$saleDate'
                    }
                },
                sales_quantity: { $sum: '$items.quantity' },
                sales_price: { $sum: '$items.price' }
            }
        },
        { $set: { sales_price: { $toDouble: '$sales_price' } } },
        { 
            $merge: {
                into: 'monthlyPhoneTransactions',
                whenMatched: 'replace'
            }
        }
    ];

    // Run the aggregation
    const cursor = collection.aggregate(pipeline);

    for await (const doc of cursor) {
        // Consume the cursor to execute the pipeline
    }
}

async function main() {
    // Connect to MongoDB
    const uri = '<connection-string>';
    const client = new MongoClient(uri);

    try {
        await client.connect();
        const database = client.db('sample_supplies');
        const sales = database.collection('sales');
        const purchaseOrders = database.collection('purchaseOrders');

        // Update immediately on startup
        await updateMonthlyPhoneTransactions(client, sales);
        await updateMonthlyPhoneTransactions(client, purchaseOrders);
        console.log('Initial update completed. Materialized view is ready.');

        // Example of a simple scheduler that updates monthly
        // This schedules the job to run at midnight on the 1st of each month
        const job = schedule.scheduleJob('0 0 1 * *', async function() {
            try {
                await updateMonthlyPhoneTransactions(client, sales);
                await updateMonthlyPhoneTransactions(client, purchaseOrders);
                console.log(`Scheduled update completed at ${new Date().toISOString()}`);
            } catch (err) {
                console.error('Error during scheduled update:', err);
            }
        });

        console.log('Scheduler is running. Press Ctrl+C to exit.');

        // Keep the process running
        process.stdin.resume();

    } catch (err) {
        console.error('Error:', err);
    } finally {
        await client.close();
    }
}

main().catch(console.error);

```

Replace `<connection-string>` with the connection string for your
Atlas cluster or local Atlas deployment.

Atlas Cluster

Your connection string should use the following format:

```
mongodb+srv://<db_username>:<db_password>@<clusterName>.<hostname>.mongodb.net
```

To learn more, see [Driver](connect-via-driver).

Local or Self-Managed

Your connection string should use the
following format:

```
mongodb://localhost:<port-number>/?directConnection=true
```

To learn more, see [Connection Strings](manual/reference/connection-string).

**Input:**

```shell
node create-update-view.js
```

**Output:**

```
Initial update completed. Materialized view is ready.
Scheduler is running. Press Ctrl+C to exit.
```

